using UnityEngine;

/// <summary>
/// Semente — concede <see cref="amount"/> Sementes (<c>PlayerProgress.GiveSementes</c>).
/// Sem contador por área (Sementes não fazem parte de AreaData/AreaProgress —
/// são um recurso global "espalhado" pelo nível).
/// </summary>
public class SementePickup : PickupBase
{
    [Header("Semente")]
    [Tooltip("Quantidade de Sementes concedidas.")]
    [Min(1)] public int amount = 1;

    public override PickupType Type => PickupType.Semente;

    protected override void GrantReward()
    {
        PlayerProgress.Instance?.GiveSementes(amount);
    }
}
